function ModelBattle:OnReconnect()
    local battleStatementList = self:GetBattleStatementList()
    for k, v in pairs(battleStatementList) do
        v:CheckResendReqResult()
        ---重发结算请求
        v:CheckResendReqCombat() ---重发战斗请求
    end
end

