local function _FillFormationPbData(pbFormation, dataFormation, combatType, isUseCfgFormation)
    local data = pbFormation
    data.formationType = combatType or LCombatTypeConst.COMBAT_MAIN
    data.teamIndex = 0
    data.formationRefId = dataFormation.formationRefId or 1

    -- 【G公共支持】删除神器功能相关数据
    -- data.artifactId = dataFormation.artifactId or 0

    local pbGrids = data.grids
    for k, v in ipairs(dataFormation.grids or {}) do
        local girld = pbGrids:add()
        girld.id = tostring(v.id)
        girld.grid = v.grid
    end

    if isUseCfgFormation then
        local draconicStarRefIds = data.draconicStarRefIds

        local checkRefIds = dataFormation.draconicStarRefIds or dataFormation.treasureSkilIds
        for i, v in ipairs(checkRefIds or {}) do
            draconicStarRefIds:append(v)
        end
    end
    local divineWeaponStarRefIds = data.divineWeaponStarRefIds
    local checkRefIds = dataFormation.divineWeaponStarRefIds --or dataFormation.treasureSkilIds
    for i, v in ipairs(checkRefIds or {}) do
        divineWeaponStarRefIds:append(v)
    end
    -- local treasureSkilIds = data.treasureSkilIds
    -- for i,v in ipairs(dataFormation.treasureSkilIds or {}) do
    -- 	treasureSkilIds:append(v)
    -- end

    -- local pasvList = data.treasurePassiveSkill
    -- for k,v in ipairs(dataFormation.treasurePassiveSkill or {}) do
    -- 	pasvList:append(v)
    -- end

    -- 【C宠物系统】删掉宠物系统相关
    -- for k,v in ipairs(dataFormation.petFights or {}) do
    -- 	data.petFights:append(v)
    -- end

    -- for k,v in ipairs(dataFormation.petHelps or {}) do
    -- 	data.petHelps:append(v)
    -- end
end

function ModelBattle:OnCombatReq(battleInfo)

    local pb = LProtoHelper.CreateProto(LProtoIds.CombatReq)
    pb.combatType = battleInfo.combatType

    local combatType = battleInfo.combatType
    local formationA = battleInfo.formationA
    local formationB = battleInfo.formationB
    local relFormation = battleInfo.relFormation

    local isUSeCfgFormation = false
    if self._isUseCfgFormation[battleInfo.combatType] then
        isUSeCfgFormation = true
    end

    local isUseCfgFormationEach = false
    if self._isUseCfgFormationEach[battleInfo.combatType] then
        isUseCfgFormationEach = true
    end

    isUSeCfgFormation = isUSeCfgFormation or isUseCfgFormationEach

    if formationA then
        _FillFormationPbData(pb.atkFormation, formationA, combatType, isUSeCfgFormation)
    end

    if formationB then
        _FillFormationPbData(pb.defFormation, formationB, combatType, isUseCfgFormationEach)
    end

    if relFormation then
        _FillFormationPbData(pb.relFormation, relFormation, combatType)
    end

    if battleInfo.targetId then
        pb.targetId = battleInfo.targetId
    end

    local data = {
        skipBattle = battleInfo.skipBattle and 1 or 0,
        targetId = battleInfo.targetId,
        battleName = battleInfo.battleName,
        battleRefId = battleInfo.battleRefId,
        buffId = battleInfo.buffId,
        sid = battleInfo.sid,
        pageId = battleInfo.pageId,
        entryId = battleInfo.entryId,
        x = battleInfo.x,
        y = battleInfo.y,
        towerType = battleInfo.towerType,
        eventRefId = battleInfo.eventRefId,
        bossTowerBossId = battleInfo.bossTowerBossId,
        bossTowerPkType = battleInfo.bossTowerPkType,
        autoBuff = battleInfo.autoBuff or 0,
        activityData = {
            rewardBoxData = battleInfo.rewardBoxData,
            mapRefId = battleInfo.mapRefId,
            sid = battleInfo.sid,
            targetId = battleInfo.targetId
        },
        rank = battleInfo.rank,
        fightType = battleInfo.fightType,
        dreamLandId = battleInfo.dreamLandId
    }

    if battleInfo.conditionList then
        data.activityData.conditionList = battleInfo.conditionList
    end
    if battleInfo.pageId then
        data.activityData.pageId = battleInfo.pageId
    end
    if battleInfo.entryId then
        data.activityData.entryId = battleInfo.entryId
    end
    if battleInfo.combatType == LCombatTypeConst.COMBAT_ACTIVITY_155 then
        data.targetName = battleInfo.otherName
    end

    local str = JSON.encode(data)

    pb.jParameter = str

    SendMessage(pb, LProtoIds.CombatReq)

    self:RecordBattleLife(battleInfo.combatType, true)

    self:ClearReportPrepare(combatType)
end

function ModelBattle:OnCombatResultReq(reportId, combatType, isCancal)
    local cancel = isCancal and 1 or 0
    local pb = LProtoHelper.CreateProto(LProtoIds.CombatResultReq)
    pb.reportId = reportId
    pb.cancel = cancel
    pb.combatType = combatType
    SendMessage(pb, LProtoIds.CombatResultReq)

    local battleStatement = self:GetBattleStatement(combatType)
    if battleStatement then
        battleStatement:OnReqCombatResult()
    end

    if combatType == LCombatTypeConst.COMBAT_MAIN then
        self._isReqMainResult = true
    end

    self:RecordBattleLife(combatType, true)
end

