function ModelBattle:OnRespTestCombatResp(pb, ret)

    local battleStatement = self:GetBattleStatementList()[LCombatTypeConst.COMBAT_TEST_BATTLE]
    if not battleStatement then
        return
    end

    battleStatement:OnTestCombatResp(pb)
end

function ModelBattle:CombatRewardReq(reportId)
    local pb = LProtoHelper.CreateProto(LProtoIds.CombatRewardReq)
    pb.reportId = reportId
    SendMessage(pb, LProtoIds.CombatRewardReq)
end

function ModelBattle:OnCombatResultResp(pb, flag)
    local combatType = pb.combatType
    if flag ~= 0 and combatType == LCombatTypeConst.COMBAT_DESIRETRAIL and gModelDesireTrail:IsSweeping(false) then
        gModelDesireTrail:SaveSweepResult(pb)
        return
    end

    if combatType == LCombatTypeConst.COMBAT_MAIN then
        self._isReqMainResult = false
    end

    self:CancelWaitReqCombat(combatType)

    if self:IsEndlessCombat(combatType) then
        gModelEndles:ClearNewSelectBuff()
    end
    local battleStatement = self:GetBattleStatement(combatType)
    if battleStatement then
        battleStatement:OnRespCombatResult()
    end

    self:RecordBattleLife(combatType, false)

    local resultKey = pb.reportId
    if self:IsMultiReportCombatType(combatType) then
        local strList = {}
        for k, v in ipairs(pb.multReportIds) do
            table.insert(strList, v)
        end

        resultKey = table.concat(strList, '|')
    end
    local isFromBack = gLFightManager:GetBattleState(resultKey)

    local isCancal = pb.cancel == 1
    if isCancal then
        return
    end

    self:BattleFinish(combatType)

    if pb.winner == 2 then
        self:RecordFail(combatType)
    elseif pb.winner == -1 then
        --超时数据已删除
        if not isFromBack then
            local retFunc = self:GetReturnFun(combatType)
            if retFunc then
                retFunc()
            end
        end

        if combatType == LCombatTypeConst.COMBAT_MAIN then
            local battleNode = gModelInstance:GetBattleNode()
            gModelGuide:SetWaitGuideByNode(battleNode) --先记录触发引导
        end
        return
    elseif pb.winner == 1 then
        if combatType == LCombatTypeConst.COMBAT_MAIN then
            --gModelInstance:SetBattleNode(-1) --标记关卡已过
            gModelGuide:OnMainAccount(pb) --先记录触发引导
            FireEvent(EventNames.ON_MAIN_BATTLE_FINISHED, pb.battleNode)
        end

        self:ClearFailCnt(combatType)
    end
    self:SetCombatResult(pb, combatType)

    --local data =
    --{
    --	level = gModelPlayer:GetPlayerLv(),
    --	exp = gModelPlayer:GetPlayerExp(),
    --}
    --
    --self:SetCurPlayerInfo(combatType,data)



    local func = self._combatTypeResultFunc[combatType]
    if func then
        func(pb, isFromBack)
    end
    gLFightManager:ClearBattleState(pb.reportId)
    FireEvent(EventNames.ON_BATTLE_FINISHED, combatType, pb.winner)

    -- 1-1 , 1- 2 自动进入布阵
    if combatType == LCombatTypeConst.COMBAT_MAIN then
        gModelGuide:CheckInstanceAutoGotoNext(pb.battleNode)
    end
end

function ModelBattle:OnCombatResp(pb)
    local combatType = pb.combatType
    self:SaveCombatResp(pb)

    self:RecordBattleLife(combatType, true)

    self:CancelWaitReqCombat(combatType)

    local isGameNotReady = not GF.IsInMainScene() or LGameRunMode.IsLoading()
    if isGameNotReady then
        local cacheOfflineCombat = self._cacheOfflineCombat or {}
        table.insert(cacheOfflineCombat, pb)
        self._cacheOfflineCombat = cacheOfflineCombat
    else
        self:OnCombatDataRet(pb)
    end


end

function ModelBattle:SaveCombatResp(pb)
    local combatType = pb.combatType
    -- 目前只有少女试炼需要
    if combatType ~= LCombatTypeConst.COMBAT_ACTIVITY_155 then
        return
    end
    self._combatRespMap = self._combatRespMap or {}
    self._combatRespMap[pb.reportId] = pb
end

function ModelBattle:GetCombatRespPb(reportId)
    return self._combatRespMap and self._combatRespMap[reportId]
end

function ModelBattle:CancelWaitReqCombat(combatType)
    local battleStatement = self:GetBattleStatement(combatType)
    if battleStatement then
        battleStatement:OnRespCombat()
    end
end

function ModelBattle:OnCombatReportCreateFinishResp(pb)

    self:RecordReportPrepare(pb.combatType, pb.id)

    local battleStatementList = self:GetBattleStatementList()
    local battleStatement = battleStatementList[pb.combatType]
    if battleStatement then
        battleStatement:OnCombatReportOk(pb)
    end
end

function ModelBattle:CheckCacheOfflineCombat()
    local combatList = self._cacheOfflineCombat
    if not combatList then
        return
    end
    self._cacheOfflineCombat = nil
    for k, pb in ipairs(combatList) do
        local combatData = self:GetOffLineBattleData(pb)
        if combatData then
            local combatType = combatData.combatType
            local startOffline = true
            if not self:CheckModelDataOK(combatType) then
                startOffline = false
                self:AddWaitStartCombatList(combatData)
            end

            if combatType == LCombatTypeConst.COMBAT_MAIN then
                local battleNode = gModelInstance:GetBattleNode()
                local noNeed = false
                if gModelPlot:IsStoryInstance(battleNode) then
                    noNeed = true
                end

                if gModelPlot:IsDogInstance(battleNode) then
                    noNeed = true
                end

                if noNeed then
                    local reportId = combatData.reportId
                    self:OnCombatResultReq(reportId, combatType)
                    startOffline = false
                end
            end

            if startOffline then
                self:StartFromCombatResp(combatData)
            end
        end
    end
end

function ModelBattle:OnPKReq(playerId, serverId)
    local pb = LProtoHelper.CreateProto(LProtoIds.PKReq)
    pb.playerId = playerId
    pb.serverId = serverId or 0
    SendMessage(pb, LProtoIds.PKReq)
end

function ModelBattle:OnShareFormationPKReq(fileUrl)
    --分享阵容pk
