    SendMessage(pb, LProtoIds.ShareFormationPKReq)
end

function ModelBattle:ReqBattleAccountInfo(reportId, combatType, isWin)
    local isFromBack = gLFightManager:GetBattleState(reportId)
    if self:IsEndlessCombat(combatType) and isWin then
        self:StartNextBattle(combatType, isFromBack)
    else
        self:OnCombatResultReq(reportId, combatType)
    end
end

function ModelBattle:CheckShowNext(isWin, curNode)
    if not isWin then
        return false
    end

    local cfg = gModelInstance:GetMissionCfg(curNode)
    if not cfg then
        return false
    end
    local nextInstanceId = cfg.NextinstanceId
    if nextInstanceId < 0 then
        return false
    end
    local canEnter = gModelInstance:CanEnterBattleNode(nextInstanceId)
    if not canEnter then
        return false
    end
    local hasPlot = gModelPlot:NodeTriggerPlot(nextInstanceId)
    if hasPlot then
        return false
    end
    local startNextChanllge = gModelInstance:GetInstancePara("NextChanllge")
    startNextChanllge = startNextChanllge and tonumber(startNextChanllge) or 0
    local cfgAllow = nextInstanceId > startNextChanllge
    if not cfgAllow then
        return false
    end

    local hasWaitGuide = gModelGuide:HasWaitGuide()
    if hasWaitGuide then
        return false
    end
    return true
end

function ModelBattle:CanAutoNextMain()
    local battleNode = gModelInstance:GetRawBattleNode()

    if battleNode < 0 then
        return false
    end
    local cfg = gModelInstance:GetMissionCfg(battleNode)
    if not cfg then
        return false
    end

    local canEnter = gModelInstance:CanEnterBattleNode(battleNode)
    if not canEnter then
        return false
    end

    local hasPlot = gModelPlot:NodeTriggerPlot(battleNode)
    if hasPlot then
        return false
    end

    return true
end

