function ModelBattle:ShowMainAccount(pb, isFromBack)
    gModelInstance:RecordChallengeCd() --主线推图cd

    if not pb then
        return
    end

    -- 继续下一关 or 指引则不显示按钮
    local curNode = pb.battleNode

    if gModelPlot:IsStoryInstance(curNode) then
        --剧情关卡，不弹结算
        return
    end

    -- 屏蔽结算
    if gModelGuide:IsGuideInstance(curNode) then
        return
    end

    local isWin = pb.winner == 1
    local showNext = self:CheckShowNext(isWin, curNode)
    --第一关只显示确定按钮
    local justShowConfirm = curNode == 10010

    if isWin then
        gModelInstance:SetImproveTag()
    end
    local refId = isWin and 51001 or 51002
    self:OpenCommonResult({
        refId = refId,
        combatResult = pb,
        isFromBack = isFromBack,
        combatType = LCombatTypeConst.COMBAT_MAIN,
        showNext = showNext,
        justShowConfirm = justShowConfirm
    })
end

function ModelBattle:ShowTowerAccount(pb, isFromBack)
    local isWin = pb.winner == 1
    local refId = isWin and 80005 or 80007
    local combatType = pb.combatType
    local towerRefId = pb.towerRefId
    local towerType = gModelTower:GetTowerTypeByCombatTyep(combatType)
    local ref = gModelTower:GetTowerLayer(towerType, towerRefId)
    local layer = ref.floorNum
    local layerNum = gModelTower:GetTowerLayerNum(towerType)
    local showNext = true
    if towerType ~= ModelTower.RACE_COM then
        --local ref = gModelTower:GetTowerPatternRefByRefId(towerType)
        local info = gModelTower:GetTowerInfoByTowerType(towerType)
        if info.maxChallengesNum - info.battleNum <= 0 then
            showNext = false
        end
    end
    if layer >= layerNum then
        showNext = false
    end
    local quickNeedLv = gModelTower:GetTowerConfigRefByKey("quickChallenge")
    if gModelPlayer:GetPlayerLv() < quickNeedLv then
        showNext = false
    end
    local isConcealText = false
    local phaselayer = gModelTower:GetBehindPhaseLayer(layer, towerType)
    if phaselayer <= 0 then
        phaselayer = 0
        isConcealText = true
    end
    local other = { phaselayer }

    local num = gModelTower:GetUnlockRaceTowerNum()
    local difficultyNum = gModelTower:GetUnlockDifficultyTowerNum() - 1
    local unlockForeshowRace = gModelTower:GetTowerConfigRefByKey("unlockForeshowRace")
    local unlockForeshowDifficulty = gModelTower:GetTowerConfigRefByKey("unlockForeshowDifficulty")

    if isWin and num > 0 and unlockForeshowRace < layer then
        refId = 80013
        other = { phaselayer, num, ccClientText(12180) }
    elseif isWin and difficultyNum > 0 and unlockForeshowDifficulty < layer then
        refId = 80013
        other = { phaselayer, difficultyNum, ccClientText(12181) }
    end

    if isWin and towerType == ModelTower.RACE_COM then
        FireEvent(EventNames.ON_TOWER_PASS, layer)
    end

    local hasGuide = gModelGuide:HasWaitGuide()

    self:OpenCommonResult({
        refId = refId,
        combatResult = pb,
        other = other,
        isFromBack = isFromBack,
        combatType = combatType,
        showNext = showNext and not hasGuide,
        isConcealText = isConcealText,
    })


end

