function ModelBattle:ShowFairylandBossAccount(pb, isFromBack)
    local haveBox = false
    for k, v in ipairs(pb.itemList) do
        haveBox = true
        break
    end

    local hurtCountA = tonumber(pb.hurtCountA)
    local maxCount = tonumber(pb.preMaxHurt)
    local nextNeedCount = pb.nextRewardHurt
    local isNewRecord = hurtCountA >= maxCount and maxCount > 0
    local refId
    if haveBox then
        --本次战斗获得奖励
        refId = 52501
    elseif nextNeedCount and tonumber(nextNeedCount) > 0 then
        --下一级奖励需要伤害
        refId = 52502
    else
        --已获得全部奖励
        refId = 52503
    end

    self:OpenCommonResult({
        refId = refId,
        combatResult = pb,
        other = { LUtil.PowerNumberCoversion(hurtCountA) },
        other2 = { maxCount, nextNeedCount },
        isFromBack = isFromBack,
        isNewRecord = isNewRecord,
        combatType = LCombatTypeConst.COMBAT_FAIRYLAND_BOSS,
    })
end

function ModelBattle:ShowGuildHolyBattleAttackResult(pb, isFromBack)
    local isWin = pb.winner == 1
    local refId = isWin and 100202 or 100203
    local args = pb.args
    local star = tonumber(args[1])
    local attack = StructPlayerInfo:New()
    attack:CreateByPb(pb.attack)

    local defense
    local robotInfo = {}

    local isRobot = tonumber(args[2]) == 1

    if isRobot then

        --self._robot.headIcon, self._robot.lv, self._robot.name, self._robot.image
        robotInfo.headIcon, robotInfo.lv, robotInfo.name, robotInfo.image = gModelGuildHolyBattle:GetRobotData()

        local ref = gModelPlayer:GetRoleAdventureImage(robotInfo.image)
        robotInfo.headIcon = ref.icon

    else
        defense = StructPlayerInfo:New()
        defense:CreateByPb(pb.defense)
    end

    self:OpenCommonResult({
        isHaveData = true,
        refId = refId,
        combatResult = pb,
        isFromBack = isFromBack,
        combatType = pb.combatType,
        star = star,
        attack = attack,
        defense = defense,
        isRobot = isRobot,
        robotInfo = robotInfo,
        isWin = isWin,
    })
end

