function ModelBattle:ShowSweetCountryBossAccount(pb, isFromBack)
    local haveBox = false
    for k, v in ipairs(pb.itemList) do
        haveBox = true
        break
    end

    local hurtCountA = tonumber(pb.hurtCountA)
    local maxCount = tonumber(pb.preMaxHurt)
    local nextNeedCount = tonumber(pb.nextRewardHurt)
    local isNewRecord = hurtCountA >= maxCount and maxCount > 0
    local refId
    if haveBox then
        --本次战斗获得奖励
        refId = 52501
    elseif nextNeedCount and nextNeedCount ~= -1 then
        --下一级奖励需要伤害
        refId = 52502
    else
        --已获得全部奖励
        refId = 52503
    end

    self:OpenCommonResult({
        refId = refId,
        combatResult = pb,
        other = { LUtil.PowerNumberCoversion(hurtCountA) },
        other2 = { maxCount, nextNeedCount },
        isFromBack = isFromBack,
        isNewRecord = isNewRecord,
        combatType = LCombatTypeConst.COMBAT_SWEETCOUNTRY_BOSS,
    })
end

