function ModelBattle:ShowEndlessAccount(pb, isFromBack)
    local ref = gModelEndles:GetEndlessRefByCombatTyep(pb.combatType)

    local nowNum, maxNum = 0, 0
    local name = ref.name ~= "" and ccLngText(ref.name) or ""
    local nowNode = pb.battleNode
    local maxNode = pb.endlessMaxNode
    local initNode = pb.endlessInitNode
    if nowNode > 0 then

        local nowRef = gModelEndles:GetEndlessCheckpointRefByRefId(nowNode)
        local curNum = nowRef.id
        if nowRef.nextRedId > 0 then
            local initRef = gModelEndles:GetEndlessCheckpointRefByRefId(initNode)
            local initNum = initRef.id

            local endlessRef = gModelEndles:GetEndlessRefByType(ref.type)
            local max = tonumber(endlessRef.everydayMax)
            if max > 0 then
                local todayNum = curNum - initNum + 1
                if todayNum < max then
                    curNum = curNum - 1
                end
            else
                curNum = curNum - 1
            end
        end
        nowNum = curNum
    end
    if maxNode > 0 then
        local maxRef = gModelEndles:GetEndlessCheckpointRefByRefId(maxNode)
        maxNum = maxRef.id
    end

    local initNode = initNode
    local isWin = true
    if initNode == nowNode then
        isWin = false
    end

    local refId = isWin and 140000 or 140003

    self:OpenCommonResult({
        refId = refId,
        combatResult = pb,
        isFromBack = isFromBack,
        combatType = pb.combatType,
        other = {
            name,
            nowNum,
            maxNum
        },
        isWin = isWin,
    })

end

