-- 退出回放提示
function ModelBattle:IsExitPK(index)
    local curBattle = gLFightManager:GetCurBattleUnit()
    if not curBattle then
        return false
    end

    local combatType = curBattle:GetCombatType()
    local videoType = curBattle:GetVideoType()
    for i, v in pairs(self._exitTipsList) do
        if v.combatType == combatType and not curBattle:IsEndExecute() then

            local extraFunc = function()
                FireEvent(EventNames.CHANGE_MAIN_BTN_WHATEVER, index)
            end

            local func = function()
                self:RecordExitByBottomClick(combatType, index)
                local noEndFunc = videoType == LVideoTypeConst.ARENA_RANK or videoType == LVideoTypeConst.CROSS_GRADING
                if combatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO_SIMULATION then
                    noEndFunc = true
                end
                gLFightManager:SkipBattleAll(combatType, true, noEndFunc, extraFunc)

                local hasLvWnd = self:HasLevelUpWnd()
                if not hasLvWnd then
                    FireEvent(EventNames.CHECK_WAIT_GUIDE)
                end
                self._exitTipsList[i].tips = nil
            end

            local refId = combatType == LCombatTypeConst.COMBAT_PK and 51501 or 51701
            self._exitTipsList[i].tips = GF.OpenWnd("UIOrdinTip", { refId = refId, func = func })
            return true
        end
    end

    return false
end

function ModelBattle:RecordExitByBottomClick(combatType, record)
    if not combatType then
        return
    end
    if not self._recordExitMap then
        self._recordExitMap = {}
    end

    self._recordExitMap[combatType] = record
end

function ModelBattle:GetBottomClickIndex(combatType)
    return self._recordExitMap and self._recordExitMap[combatType]
end

function ModelBattle:ClearTipWnd(combatType)
    for k, v in pairs(self._exitTipsList) do
