function ModelBattle:GetOffLineBattleData(pb)
    local curTime = GetTimestamp()
    local offlineTime = (curTime - tonumber(pb.startTime) / 1000)
    local otherName
    local combatType = pb.combatType
    local refId = pb.refId
    local monsterId = pb.monsterId
    local targetId = nil

    if combatType == LCombatTypeConst.COMBAT_DREAMTRIP then
        otherName = gModelFastDreamTrip:GetDreamTripEventNameByRefId(refId)
    elseif combatType == LCombatTypeConst.COMBAT_WONDERLAND then
        otherName = gModelWonderland:GetEventName(refId)
    elseif combatType == LCombatTypeConst.COMBAT_DESIRETRAIL then
        otherName = gModelDesireTrail:GetEventName(refId)
    elseif combatType == LCombatTypeConst.COMBAT_INVASION then
        otherName = gModelInvasion:GetEventName(refId)
        --elseif self:IsTimeCorridorCombat(combatType) then
        --	otherName =  gModelTimeCorridor:GetEventName(refId)
    else
        if monsterId > 0 then
            local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(tonumber(pb.monsterId))
            if monsterFormationRef then
                otherName = ccLngText(monsterFormationRef.name)
            else
                LogError("MonsterFormationRef中不存在" .. pb.monsterId)
            end
        else
            otherName = pb.targetName
        end
    end
    if combatType == LCombatTypeConst.COMBAT_CRUSADE_AGAINST then
        targetId = refId
    end
    if combatType == LCombatTypeConst.COMBAT_BADGE_GAME then
        targetId = refId
    end

    local multReportIds = {}
    if pb.multReportIds then
        for k, v in ipairs(pb.multReportIds) do
            table.insert(multReportIds, v)
        end
    end
    local activityData = pb.activityData
    local activityDataList = {}
    if not string.isempty(activityData) then
        activityDataList = JSON.decode(activityData)
    end

    local meName = gModelPlayer:GetPlayerName()
    otherName = otherName or ""
    local combatData = {
        meName = meName,
        otherName = otherName,
        offlineTime = offlineTime,
        isBattleToBackground = true,
        combatType = combatType,
        monsterId = pb.monsterId,
        targetName = pb.targetName,
        targetLevel = pb.targetLevel,
        isRepeat = pb.isRepeat,
        startTime = pb.startTime,
        reportId = pb.reportId,
        serverId = pb.serverId,
        targetId = targetId,
        multReportIds = multReportIds, --试炼之藤困难模式
        mapRefId = activityDataList.mapRefId,
        rewardBoxData = activityDataList.rewardBoxData
    }

    return combatData

end
