function ModelBattle:GetBattleMapRes(combatData)
    local mapNameFunc = self._getMapNameFunc
    if not mapNameFunc then
        mapNameFunc = {
            [LCombatTypeConst.COMBAT_MAIN] = function(combatData)
                return gModelInstance:GetCurMissionCfgMapName()
            end,
            [LCombatTypeConst.COMBAT_DUNGEON_DAILY] = function(combatData)
                local dungeonId = combatData.dungeonId
                --local name = gModelDreamFountain:GetMapName(dungeonId)

                local name = gModelDungeonDaily:GetMapName(dungeonId)
                return name
            end,
            [LCombatTypeConst.COMBAT_GUILD_BRAVE] = function(combatData)
                return gModelGuild:GetGuildBraveMap()
            end,
            [LCombatTypeConst.COMBAT_WONDERLAND] = function(combatData)
                local mapId = gModelWonderland:GetBattleMapId()
                local map = self:GetSceneNameBySceneId(mapId)
                return map
            end,
            [LCombatTypeConst.COMBAT_DESIRETRAIL] = function(combatData)
                local mapId = gModelDesireTrail:GetBattleMapId()
                local map = self:GetSceneNameBySceneId(mapId)
                return map
            end,
            [LCombatTypeConst.COMBAT_BATTLE_VIDEO_SIMULATION] = function(combatData)
                local mapRefId = combatData.mapRefId
                if mapRefId then
                    return self:GetSceneNameBySceneId(mapRefId)
                end
            end,
            [LCombatTypeConst.COMBAT_ACTIVITY] = function(combatData)
                local map = combatData.map
                if not string.isempty(map) then
                    return map
                end
            end,
            [LCombatTypeConst.COMBAT_FAIRYLAND_BOSS] = function(combatData)
                local mapRefId = combatData.mapRefId
                local name = self:GetSceneNameBySceneId(mapRefId)
                return name
            end,
            -- [LCombatTypeConst.COMBAT_HALLOWEEN_BOSS] = function(combatData)
            -- 	local mapRefId = combatData.mapRefId
            -- 	local name =  self:GetSceneNameBySceneId(mapRefId)
            -- 	return name
            -- end,
            [LCombatTypeConst.COMBAT_SWEETCOUNTRY_BOSS] = function(combatData)
                local mapRefId = combatData.mapRefId
                local name = self:GetSceneNameBySceneId(mapRefId)
                return name
            end,
            [LCombatTypeConst.COMBAT_NEW_HERO_THEME_CHAPTER] = function(combatData)
                local mapRefId = combatData.mapRefId
                local name = self:GetSceneNameBySceneId(mapRefId)
                return name
            end,
            -- [LCombatTypeConst.COMBAT_NEW_HERO_THEME_B_CHAPTER] = function(combatData)
            -- 	local mapRefId = combatData.mapRefId
            -- 	local name =  self:GetSceneNameBySceneId(mapRefId)
            -- 	return name
            -- end,
            [LCombatTypeConst.COMBAT_ACTIVITY_PLOT_COPY] = function(combatData)
                local mapRefId = combatData.mapRefId
                local name = self:GetSceneNameBySceneId(mapRefId)
                return name
            end,
            [LCombatTypeConst.COMBAT_ENDLES] = function(...)
                return self:GetEndlessBattleMap(...)
            end,
            [LCombatTypeConst.COMBAT_ENDLES_FIRE] = function(...)
                return self:GetEndlessBattleMap(...)
            end,
            [LCombatTypeConst.COMBAT_ENDLES_WATER] = function(...)
                return self:GetEndlessBattleMap(...)
            end,
            [LCombatTypeConst.COMBAT_ENDLES_WIND] = function(...)
                return self:GetEndlessBattleMap(...)
            end,
            [LCombatTypeConst.COMBAT_ENDLES_LIGHT_DARK] = function(...)
                return self:GetEndlessBattleMap(...)
            end,
            [LCombatTypeConst.COMBAT_DREAMTRIP] = function(...)
                local mapId = gModelFastDreamTrip:GetDreamTripMapId()
                local map = self:GetSceneNameBySceneId(mapId)
                return map
            end,

        }
        self._getMapNameFunc = mapNameFunc
    end

    local func = self._getMapNameFunc[combatData.combatType]
    if func then
        return func(combatData)
    else
        return self:GetSceneNameByCombatType(combatData.combatType)
    end
end

