    return ref.bgMusic
end

function ModelBattle:GetCombatTypeName(combatType)
    local ref = GameTable.BattleGameRef[combatType]
    if not ref then
        return ""
    end

    return ccLngText(ref.name)
end

function ModelBattle:GetSceneNameByCombatType(combatType)

    local ref = GameTable.BattleGameRef[combatType]
    if ref then
        local scene = tonumber(ref.fightScene)
        if scene and not string.isempty(scene) and scene > 0 then
            return gModelInstance:GetSceneNameBySceneId(scene)
        end
    end
end

function ModelBattle:GetSceneNameBySceneId(sceneId)
    if not sceneId then
