    mapName = sceneRef and sceneRef.name or nil
    return mapName
end

function ModelBattle:GetBattleUnitFightSpeed()
    local speedInfo = LPlayerPrefs.fightSpeed
    local strs = string.split(speedInfo, "|")
    local curSpeed = tonumber(strs[1])
    local maxSpeed = tonumber(strs[2])
    return curSpeed, maxSpeed
end

function ModelBattle:SetBattleUnitFightSpeed(value, maxSpeed)
    value = value or 1
    local str = string.format("%s|%s", value, maxSpeed)
    LPlayerPrefs.SetFightSpeed(str)
end

function ModelBattle:GetBattleDetailsDataByReport(reportTable)
    local result = {}
    result.detailsA = {}
    result.detailsB = {}

    local combatType = tonumber(reportTable.combatType)
    if combatType == LCombatTypeConst.COMBAT_GUILD_BRAVE or combatType == LCombatTypeConst.COMBAT_INVASION_BOSS or combatType == LCombatTypeConst.COMBAT_TYPE_32 then
        -- 公会副本无论实际结果是什么，表现都要必胜
        result.winner = 1
    else
        result.winner = reportTable.winner
    end

    local details = reportTable.details
    local formationA = details.detailsA
    local formationB = details.detailsB

    result.hurtCountA = details.hurtCountA
    result.injuredCountA = details.injuredCountA
    result.treatCountA = details.treatCountA

    result.hurtCountB = details.hurtCountB
    result.injuredCountB = details.injuredCountB
    result.treatCountB = details.treatCountB

    for i, v in ipairs(formationA) do
        local data = {
            hurt = v.hurt,
            injured = v.injured,
            treat = v.treat,
        }
        result.detailsA[v.heroRefId] = data
    end

    for i, v in ipairs(formationB) do
        local data = {
            hurt = v.hurt,
            injured = v.injured,
            treat = v.treat,
        }
        result.detailsB[v.heroRefId] = data
    end

    return result
end

function ModelBattle:OnClickShamBattle(refId, func)

    gModelGeneral:RecordGameState()

    local warReportFile = gModelBattle:GetWrReportFileByRefId(refId)
    local reportId = warReportFile
    local battleEndfun = function()

        gModelGeneral:RecoverGameState()
    end
    local map = gModelBattle:GetWrReportMapByRefId(refId)
    local round = gModelBattle:GetWrReportRoundByRefId(refId)
    local skip = gModelBattle:GetWrReportSkipByRefId(refId)
    local accelerate = gModelBattle:GetWrReportAccelerateByRefId(refId)
    local meName = gModelBattle:GetWrReportNameByRefId(refId, true)
    local otherName = gModelBattle:GetWrReportNameByRefId(refId, false)

    local battleCfg = gModelBattle:GetWarReportRefByRefId(refId)
    if not battleCfg then
        printErrorN(string.format("not battle cfg refId  %s ", refId))
        return
    end
    local accelerateNum = battleCfg.accelerateNum
    local initSpeed = battleCfg.speed
    local hideUI = battleCfg.hideUi == 1

    local combatExtraData = {
        battleEndfun = battleEndfun,
        warReportRefId = refId,
        mapRefId = map,
        round = round,
        skip = skip,
        accelerate = accelerate,
        meName = meName,
        otherName = otherName,
        accelerateNum = accelerateNum,
        initSpeed = initSpeed,
        hideUI = hideUI,
    }
    gLFightManager:StartSimulationBattle(reportId, combatExtraData)
end

function ModelBattle:GetOtherName(combatData)
    local combatType = combatData.combatType
    if gModelTower:GetIsTowerTypeByCombatType(combatType) then
        local towerType = gModelTower:GetTowerTypeByCombatTyep(combatType)
        local layer = gModelTower:GetCurrLayer(towerType)
        local otherName
        if towerType == ModelTower.RACE_TYPE_99 then
            otherName = gModelTower:GetTowerCurrNameByType(ModelTower.RACE_TYPE_99)

            local monsterId = nil
            monsterId = gModelBattle:GetMonsterId(combatType)
            local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterId)
            if monsterFormationRef then
                otherName  = ccLngText(monsterFormationRef.name)
            end
        else
            otherName = string.replace(ccClientText(12162), layer)
        end

        return otherName
    elseif self:IsEndlessCombat(combatType) then
        local specialType = combatData.specialType
        local endlesInfo = gModelEndles:GetEndlesData(specialType)
        if not endlesInfo then
            printErrorN("endlessInfo[type] not find;  type = " .. (specialType or "nil"))
            return ""
        end
        local nodel = endlesInfo.nowNode > 0 and endlesInfo.nowNode or endlesInfo.initNode
        local ref = gModelEndles:GetEndlessCheckpointRefByRefId(nodel)
        local monsterRef = gModelHero:GetMonsterFormationRefByRefId(ref.monster)
        if not monsterRef then
            printErrorN("ModelBattle nil ref MonsterFormationRef :" .. ref.monster)
            return ""
        end
        return ccLngText(monsterRef.name)
    elseif (LCombatTypeConst.COMBAT_GUILD_BRAVE == combatType) then
        local info = gModelGuildBoss:GetGuildBraveInfo()
        local refId = info.braveId
        local ref = gModelGuildBoss:GetNewGuildDungeonMonsterRefByRefId(refId)
        local otherName = ccLngText(ref.name)
        return otherName
        -- 【G公共支持】删掉联盟领主玩法
        -- elseif LCombatTypeConst.COMBAT_TYPE_32 == combatType then
        -- 	local bossInfo = gModelGuildFeudal:GetBossInfo()
        -- 	local bossRefId = bossInfo.bossRefId
        -- 	local bossRef = gModelGuildFeudal:GetGuildFeudalBossRefByRefId(bossRefId)
        -- 	local otherName = ccLngText(bossRef.name)
        -- 	return otherName
    elseif combatType == LCombatTypeConst.COMBAT_MAIN then
        local cfg = gModelInstance:GetCurMissionCfg()
        if cfg then
            local otherName = ccLngText(cfg.nameWorld)
            return otherName
        end
    elseif combatType == LCombatTypeConst.COMBAT_DUNGEON_DAILY then
        local monsterId = self:GetMonsterId(combatType, combatData)
        local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterId)
        if monsterFormationRef then
            local otherName = ccLngText(monsterFormationRef.name)
            return otherName
        end
        -- elseif gModelBossTower:IsBossTowerCombat(combatType) then
        -- 	return gModelBossTower:GetBossTowerBossNameByRefIdAndCombatType(combatData.bossId,combatType)
    else
        local monsterId = self:GetMonsterId(combatType, combatData)
        local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterId)
        if monsterFormationRef then
            local otherName = ccLngText(monsterFormationRef.name)
            return otherName
        end
    end
end

