function ModelBattle:FirstGotoMainBattle()
    local combatType = LCombatTypeConst.COMBAT_MAIN
    if not gModelFormation:IsAnyValidHeroInFormation(combatType) then
        self:DoOneKeyMainBattle()
        return
    end
    local combatData = {
        combatType = combatType,
        meName = gModelPlayer:GetPlayerName(),
        isBattleToBackground = false
    }
    combatData.otherName = self:GetOtherName(combatData)
    self:StartAfterSetFormation(combatData)
end

function ModelBattle:TryGotoMainBattle()
    local combatType = LCombatTypeConst.COMBAT_MAIN
    if not gModelFormation:IsAnyValidHeroInFormation(combatType) or gModelInstance:IsAutoOneKeyUp() then
        self:DoOneKeyMainBattle()
        return
    end

    local combatData = {
        combatType = LCombatTypeConst.COMBAT_MAIN,
        meName = gModelPlayer:GetPlayerName(),
        isBattleToBackground = false
    }
    combatData.otherName = self:GetOtherName(combatData)
    self:StartAfterSetFormation(combatData)
end

---主线一键自动上阵战斗
function ModelBattle:DoOneKeyMainBattle()
    local combatType = LCombatTypeConst.COMBAT_MAIN
    local formation = gModelFormation:GetFormation(combatType)
    local formationType = 1
    -- 【G公共支持】删除神器功能相关数据
    -- local artifact = 0
    -- local treasureSkilIds = {}
    if formation then
        -- 【G公共支持】删除神器功能相关数据
        -- artifact = formation.artifactId or 0
        formationType = formation.formationType
        -- treasureSkilIds = formation.treasureSkilIds or {}
    end
    if formationType == 0 then
        formationType = 1
    end
    local indexToIdList = gModelFormation:GetOneKeyUpFormation(LCombatTypeConst.COMBAT_MAIN, formationType)
    local matrix = gModelFormation:GetFormationPosByRefId(formationType)
    local grids = {}
    for index, id in pairs(indexToIdList) do
        local grid = matrix[index]
        local data = {}
        data.id = id
        data.grid = grid
        table.insert(grids, data)
    end

    local meName = gModelPlayer:GetPlayerName()
    local combatData = {
        ---一个类型可能只是保存战斗阵型,也可以是战斗
        ---阵型设置相关数据
        combatType = combatType,
        formationRefId = formationType,
        grids = grids,
        -- 【G公共支持】删除神器功能相关数据
        -- artifact = artifact,
        teamIndex = nil,
        -- treasureSkilIds = treasureSkilIds,
        ---通用战斗请求相关数据
        meName = meName,
    }
    combatData.otherName = self:GetOtherName(combatData)

    self:StartBattleReq(combatData)
end

---主线一键自动布置阵容
function ModelBattle:DoOneKeyMainFormation()
    local combatType = LCombatTypeConst.COMBAT_MAIN
    local formation = gModelFormation:GetFormation(combatType)
    local formationType = 1
    -- local artifact = 0【G公共支持】删除神器功能相关数据
    -- local treasureSkilIds = {}
    if formation then
        -- artifact = formation.artifactId or 0【G公共支持】删除神器功能相关数据
        formationType = formation.formationType
        -- treasureSkilIds = formation.treasureSkilIds or {}
    end
    if formationType == 0 then
        formationType = 1
    end
    local indexToIdList = gModelFormation:GetOneKeyUpFormation(LCombatTypeConst.COMBAT_MAIN, formationType)
    local matrix = gModelFormation:GetFormationPosByRefId(formationType)
    local grids = {}
    for index, id in pairs(indexToIdList) do
        local grid = matrix[index]
        local data = {}
        data.id = id
        data.grid = grid
        table.insert(grids, data)
    end

    table.sort(grids, function(grid1, grid2)
        return grid1.grid < grid2.grid
    end)

    local teamIndex = 0
    local data = {
        combatType = combatType,
        formationRefId = formationType,
        grids = grids,
        teamIndex = teamIndex,
        -- artifact = artifact,【G公共支持】删除神器功能相关数据
        -- treasureSkilIds = treasureSkilIds,
    }

    gModelFormation:OnlySetFormationReq(data)
end

