---从布阵开始战斗流程
function ModelBattle:StartBattleReq(combatData)
    printInfoN("StartBattleReq")

    local combatType = combatData.combatType
    local battleStatement = self:GetBattleStatementList()[combatType]
    local isInBattle = battleStatement and not battleStatement:IsCanReplace()
    if isInBattle then
        printErrorN(string.format("combat type %s is in battle", combatType))
        return
    end
    if battleStatement then
        battleStatement:Destroy()
    end

    if self:IsMultiReportCombatType(combatType) then
        battleStatement = LFightStateMulti:New()
    else
        battleStatement = LFightStatement:New()
    end

    self:GetBattleStatementList()[combatType] = battleStatement
    battleStatement:Start(combatData)

    self:RecordBattleLife(combatType, true)
end
