function ModelBattle:OnCombatDataRet(pb)
    local received = false
    for k, v in pairs(self:GetBattleStatementList()) do
        received = v:OnCombatResp(pb)
        if received then
            break
        end
    end
    if received then
        --没有找到的情况，当成离线处理
        return
    end
    local combatData = self:GetOffLineBattleData(pb)
    if not combatData then
        return
    end
    local combatType = combatData.combatType
    if not self:CheckModelDataOK(combatType) then
        self:AddWaitStartCombatList(combatData)
        return
    end

    self:StartOfflineBattle(combatData)
end

---离线战斗处理，包括断线重连
function ModelBattle:StartOfflineBattle(combatData)
    local combatType = combatData.combatType
    self:DestroyBattleStatement(combatType)

    local fullExtraData = gLFightManager:FormatBattleExtraData(combatData)
    local isSceneReady = gLFightManager:IsBattleSceneReady(combatType, fullExtraData.battleMapName)

    combatData.isBattleToBackground = not isSceneReady

    local battle = gLFightManager:GetBattleByType(combatType)
    if battle then
        battle:ExitBattleImpl()
    end
    self:StartFromCombatResp(combatData)
end

---检查模块数据是否完成初始化
function ModelBattle:CheckModelDataOK(combatType)
    if self:IsEndlessCombat(combatType) then
        local ref = gModelEndles:GetEndlessRefByCombatTyep(combatType)
        local targetType = ref.type
        local netData = gModelEndles:GetEndlesData(targetType)

        if not netData then
            return false
        end
    end

    return true
end

---添加到等待列表
function ModelBattle:AddWaitStartCombatList(combatData)
    if not self._waitCombatList then
        self._waitCombatList = {}
    end

    table.insert(self._waitCombatList, combatData)
end

---模块初始化完成是重新检查
function ModelBattle:CheckStartWaitCombat()
    if not self._waitCombatList then
        return
    end
    local cnt = #self._waitCombatList
    if cnt == 0 then
        return
    end

    for k = cnt, 1, -1 do
        local combatData = self._waitCombatList[k]
        if self:CheckModelDataOK(combatData.combatType) then
            self:StartOfflineBattle(combatData)
            table.remove(self._waitCombatList, k)
        end
    end
end

function ModelBattle:DestroyBattleStatement(combatType)
    local battleStatement = self:GetBattleStatementList()[combatType]

    if battleStatement then
        battleStatement:Destroy()
    end
    self:GetBattleStatementList()[combatType] = nil
end

function ModelBattle:BattleFinish(combatType)
    FireEvent(EventNames.ON_BATTLE_END)

    if gLFightManager:IsNoAccountWnd(combatType) then
        return
    end

    local battleStatement = self:GetBattleStatementList()[combatType]
    if not battleStatement then
        battleStatement = LFightStatement:New()
        battleStatement:SetCombatType(combatType)
        self:GetBattleStatementList()[combatType] = battleStatement
    end
    battleStatement:BattleFinish()
end

