function ModelBattle:ExistPositiveBattle()
    --战斗已开始，并且在前台的情况
    for k, v in pairs(self:GetBattleStatementList()) do
        if not v:IsCanReplace() then
            local combatData = v:GetCombatData()
            local combatType = combatData.combatType
            local curBattle = gLFightManager:GetBattleByType(combatType)
            if not curBattle then
                --已经发了协议，但是还没没进入战斗
                return true
            else
                local isBack = curBattle:IsBackgroundPlay() --进入了战斗，但是是后台
                if not isBack then
                    return true
                end
            end
        end
    end
    return false
end

