    local list = self:GetBattleStatementList()
    return list[combatType]
end

function ModelBattle:GetBattleStatementList()
    local list = self._battleStatementList
    if not list then
        list = {}
        self._battleStatementList = list
    end
    return list
end

function ModelBattle:BattlePlayBack(battleData, needCheck)

    local reportId = battleData.reportId

    if needCheck and not self:IsReportPrepare(battleData.combatType, reportId) then
        return
    end

    gLxTKData:OnTAClientEventReq(LxTKData.CLIENT_REPLAY, nil, reportId)

    local extraData = {}
    extraData.combatType = battleData.combatType
    extraData.offlineTime = 0
    extraData.isBattleToBackground = false
    extraData.meName = battleData.meName
    extraData.otherName = battleData.otherName
    extraData.isNew = true
    extraData.dungeonId = battleData.dungeonId
    extraData.battleEndfun = battleData.battleEndfun
    extraData.videoType = LVideoTypeConst.PLAYBACK
    extraData.targetId = battleData.targetId
    extraData.conditionList = battleData.conditionList

    gLFightManager:OnPlayBattleVideo(reportId, extraData, LCombatTypeConst.COMBAT_BATTLE_VIDEO)

    gLGameUI:CloseAllButExcept({ ["UIFight"] = true })

    if battleData.combatType == LCombatTypeConst.COMBAT_PK then
        gModelGeneral:RecordGameState()
    end

end

function ModelBattle:MultiBattlePlayBack(battleData, needCheck)
    local reportId = battleData.reportId

    if needCheck and not self:IsReportPrepare2(battleData.combatType, reportId) then
        return
    end
    local reportIdStr = ""
    local list = {}
    for i, v in ipairs(reportId) do
        table.insert(list, v)
    end
    reportIdStr = table.concat(list, "|")
    gLxTKData:OnTAClientEventReq(LxTKData.CLIENT_REPLAY, nil, reportIdStr)

    local extraData = {}
    extraData.combatType = battleData.combatType
    extraData.offlineTime = 0
    extraData.isBattleToBackground = false
    --extraData.meName = battleData.meName
    --extraData.otherName = battleData.otherName
    extraData.isNew = true
    extraData.dungeonId = battleData.dungeonId
    extraData.battleEndfun = battleData.battleEndfun
    extraData.videoType = LVideoTypeConst.PLAYBACK

    gLFightManager:OnPlayMultiVideo(reportId, extraData, LCombatTypeConst.COMBAT_BATTLE_VIDEO)

    gLGameUI:CloseAllButExcept({ ["UIFight"] = true })

end

function ModelBattle:ContinueBattlePlayBack(combatData, cusCombatType)
    local reportIdList = combatData.reportIdList
    local list = {}
    local reportKey = ""
    for k, v in ipairs(reportIdList) do
        table.insert(list, v)
    end

    reportKey = table.concat(list, "|")

    gLxTKData:OnTAClientEventReq(LxTKData.CLIENT_REPLAY, nil, reportKey)
    local combatType = cusCombatType and cusCombatType or LCombatTypeConst.COMBAT_CROSSGRADING_RANK
    -- local isHighStageRace=gModelHighStageRace:IsHighStageRace(combatType)
    local resultWndName = "UIringFightResult"
    local wndPara = {
        combatResult = combatData,
        wndName = resultWndName
    }
    local combatData = {
        combatType = combatType,
        reportList = combatData.reportIdList,
        isBattleToBackground = false,
        serverId = combatData.serverId,
        battleEndfun = function()
            gModelBattle:OpenCommonResult(wndPara)
        end,
        videoType = LVideoTypeConst.PLAYBACK,
        winnerNumber = combatData.winnerNumber,
    }

    self:StartContinueBattle(LCombatTypeConst.COMBAT_BATTLE_VIDEO, combatData)


end

