function ModelBattle:ReturnEndless(page, BotBtnIndx)
    FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = BotBtnIndx or LMainBtnIndexConst.CITY })
    if BotBtnIndx == 2 then
        GF.OpenWndBottom("UIOutts")
    end
    GF.OpenWndBottom("UIUendWin", { page = page })
    GF.ChangeMap("LCityMap")

    gLGameUI:CloseAllButExcept({
        ["UIUendWin"] = true
    })

end
function ModelBattle:ReturnBadgeGame(param)
    FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = LMainBtnIndexConst.OUTSKIRTS })

    local chapterId,chapterType
    local barrierRefId = checknumber(param.refId)
    if barrierRefId and barrierRefId > 0 then
        local barrierRef = GameTable.BadgeGameBarrierRef[barrierRefId]
        if barrierRef then
            chapterId = barrierRef.chapterId
            chapterType = gModelBadgeGame:GetBadgeGameChapRefType(chapterId)
        end
    end
    GF.OpenWnd("UIBrandGameWin", {
        name = "UISubBrandGame",
        chapterId = chapterId,
        chapterType = chapterType
    })
    GF.ChangeMap("LCityMap")
    GF.CloseWndByName("UIOrdinResult")
end

function ModelBattle:ReturnActivity155(param, sid)
    if not sid and param.activityData then
        local data = JSON.decode(param.activityData)
        sid = data.sid
    end

    if sid then
        GF.OpenWnd("UIActDamselTrial", { sid = sid })
    end

    GF.ChangeMap("LCityMap")
    GF.CloseWndByName("UIOrdinResult")
end

