function ModelBattle:ReturnPetDreamLand(combatResult)
    print(combatResult)
    local params = combatResult.params

    --- 2024/7/2：结算返回关闭窗口问题，新增保留 UIPeWishLandReportResult 窗口
    FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, {
        index = LMainBtnIndexConst.OUTSKIRTS,
        extraWnds = {
            ["UIPeWishLandReportResult"] = true,
        }
    })

    GF.ChangeMap("LCityMap")
    GF.OpenWndBottom("UIOutts", { childIndex = 2 })

    if not string.isempty(params) then
        local exceptsWnd, state = gModelFunctionOpen:Jump(ModelFunctionOpen.PET_DREAMLAND)
        if state then
            local paramsInfo = JSON.decode(params)
            local refId = paramsInfo and paramsInfo.refId
            if refId and refId > 0 then
                --local pointId = paramsInfo.pointId
                ---@type StructPetDreamLandData
                local serData = gModelPetDreanLand:GetPetDreamLandDataByRefId(refId)
                if serData then
                    gModelPetDreanLand:OpenPetDreamLandMain(serData, refId)
                end
            end
        end
    end

    local reportResultFunc = nil
    ---@type LWnd
    local wndIns = GF.FindFirstWndByName("UIPeWishLandReportResult")
    if wndIns then
        local argList = wndIns:GetHistory()
        reportResultFunc = function()
            GF.OpenWnd("UIPeWishLandReportResult", argList and argList.wndArgList or {})
        end
    end

    gModelPetDreanLand:OpenPetDreamLandReportResult()

    local excepts = {
        ["UIOutts"] = true,
        ["UIPeWishLand"] = true,
        ["UIPeWishLandMin"] = true,
        ["UIPeWishLandReportResult"] = true,
    }

    gLGameUI:CloseAllButExcept(excepts)

    if reportResultFunc then
        reportResultFunc()
    end
end

