function ModelBattle:ReturnWonderland()

    local combatResult = self:GetCombatResult(LCombatTypeConst.COMBAT_WONDERLAND)
    local isWin = false
    if combatResult and combatResult.winner == 1 then
        isWin = true
    end

    local autoTrigger = isWin
    local eventId = -1
    if combatResult then
        eventId = combatResult.wonderlandEventRefId
        local eventRef = gModelWonderland:GetEventConfig(eventId)
        local eventType = eventRef.type
        autoTrigger = autoTrigger and eventType ~= ModelWonderland.EVENT_TIME_LORD
    end

    FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = LMainBtnIndexConst.CITY })

    if gModelWonderland:IsInMap() then
        GF.OpenWndBottom("UIEden", { autoTrigger = autoTrigger, isFromBattle = true, eventId = eventId })
    else
        GF.OpenWndBottom("UIEdenFront")
    end

    local excepts = {
        ["UIEden"] = true,
        ["UIEdenFront"] = true,
    }

    gLGameUI:CloseAllButExcept(excepts)

    gModelWonderland:EnterWonderMap()


end

function ModelBattle:ReturnDesireTrail()
    local combatResult = self:GetCombatResult(LCombatTypeConst.COMBAT_DESIRETRAIL)
    local isWin = false
    if combatResult and combatResult.winner == 1 then
        isWin = true
    end

    if not isWin then
        if GF.FindFirstWndByName("UIDesireTrail") then
            GF.CloseWndByName("UIOrdinResult")
            return
        end
    end

    local autoTrigger = isWin
    local eventId = -1
    if combatResult then
        eventId = combatResult.wonderlandEventRefId
        local eventRef = gModelDesireTrail:GetEventConfig(eventId)
        local eventType = eventRef.type
        -- autoTrigger = autoTrigger and eventType ~= ModelWonderland.EVENT_TIME_LORD
    end

    FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = LMainBtnIndexConst.OUTSKIRTS })

    -- if gModelWonderland:IsInMap() then
    --     GF.OpenWndBottom("UIEden", { autoTrigger = autoTrigger, isFromBattle = true, eventId = eventId })
    -- else
    --     GF.OpenWndBottom("UIEdenFront")
    -- end

    local excepts = {
        ["UIDesireTrail"] = true
    }

    gLGameUI:CloseAllButExcept(excepts)

    -- gModelWonderland:EnterWonderMap()
    gModelGeneral:DesireTrailEntrance()

end

