function ModelBattle:ClearReliefTroopCacheData()
    self._cacheReliefTroop = {}
end

---援军
function ModelBattle:GetReliefTroopData(combatType, combatExtraData)
    local data = self._cacheReliefTroop and self._cacheReliefTroop[combatType] or nil
    if data then
        return true, data
    end
    if not self._cacheReliefTroop then
        self._cacheReliefTroop = {}
    end
    local reliefTroop
    if combatType == LCombatTypeConst.COMBAT_MAIN then
        local cfg = gModelInstance:GetCurMissionCfg()
        reliefTroop = cfg.reliefTroop
    else
        reliefTroop = combatExtraData.reliefTroopId
    end
    if not reliefTroop or reliefTroop <= 0 then
        return false, nil
    end

    local ref = GameTable.BattleReliefTroopRef[reliefTroop]
    if ref then
        local confirmTroopList = LxDataHelper.ParseIntList_param3(ref.confirmTroop or "", "=", ";")
        local heroReplaceList = LxDataHelper.ParseIntList_param4(ref.heroReplace or "", "=", ";")
        local freeTroopList = LxDataHelper.ParseNumber_Sign(ref.freeTroop or "", ";")
        local formation = ref.formation
        local monList = {}
        local heroList = {}
        local fixedIndex = {}
        local fixedInFormation = {}
        local monRefId = 0
        local gridIndex = 0
        local refIdRecord = {}
        local monPowerMap = {}
        local monMap = {}
        local monToHeroRefId = {}
        for k, v in ipairs(confirmTroopList) do
            monRefId = v[3]
            gridIndex = v[1]
            local index = gModelFormation:GetIndexByPos(formation, gridIndex)
            local isFixed = (v[2] == 0)
            local monsterRef = gModelHero:GetMonsterAttrByRefId(monRefId)
            local race = monsterRef.raceType
            table.insert(monList, { refId = monRefId, index = index, isFixed = isFixed, race = race })
            fixedInFormation[monRefId] = true
            if (isFixed) then
                fixedIndex[index] = index
            end
            monPowerMap[monRefId] = monsterRef.monsterPower or 0
            monMap[monRefId] = true
            monToHeroRefId[monRefId] = monsterRef.heroId
        end

        local heroRefId = 0

        for k, v in ipairs(heroReplaceList) do
            heroRefId = v[3]
            monRefId = v[4]
            gridIndex = v[1]
            local heroId = gModelHero:GetMaxPowerHeroByRefId(heroRefId)
            local isFixed = (v[2] == 0)
            local index = gModelFormation:GetIndexByPos(formation, gridIndex)
            if (heroId) then
                local race = gModelHero:GetHeroRace(heroRefId)
                table.insert(heroList, { id = heroId, index = index, fixedIndex = isFixed, race = race })
                fixedInFormation[heroId] = true
                refIdRecord[heroRefId] = true
                if (isFixed) then
                    fixedIndex[index] = index
                end
            else
                local monsterRef = gModelHero:GetMonsterAttrByRefId(monRefId)
                if monsterRef then
                    local race = monsterRef.raceType
                    table.insert(monList, { refId = monRefId, index = index, fixedIndex = isFixed, race = race })
                    fixedInFormation[monRefId] = true

                    if (isFixed) then
                        fixedIndex[index] = index
                    end
                    monPowerMap[monRefId] = monsterRef.monsterPower or 0
                    monMap[monRefId] = true
                    monToHeroRefId[monRefId] = monsterRef.heroId
                end
            end
        end

        local tmpFreeList = {}
        for k, v in ipairs(freeTroopList) do
            monRefId = v
            local monsterRef = gModelHero:GetMonsterAttrByRefId(monRefId)
            local race = monsterRef.raceType
            table.insert(tmpFreeList, { refId = monRefId, grid = 0, isFixed = false, race = race })
            monPowerMap[monRefId] = monsterRef.monsterPower or 0
            monMap[monRefId] = true
            monToHeroRefId[monRefId] = monsterRef.heroId
        end

        local dataTbl = {
            refIdRecord = {},
            refId = reliefTroop,
            cfg = ref,
            formation = formation,
            freeTroopList = tmpFreeList,
            selfHero = ref.selfHero == 1,
            monList = monList,
            heroList = heroList,
            fixedIndex = fixedIndex,
            fixedInFormation = fixedInFormation,
            monPowerMap = monPowerMap,
            monMap = monMap,
            monToHeroRefId = monToHeroRefId,
            -- treasure = ref.treasure == 1,
        }
        self._cacheReliefTroop[combatType] = dataTbl
        return true, dataTbl
    end
end


