----------------------------------------------获取怪物-----------------------------------------------
function ModelBattle:GetMonsterId(_combatType, battleData)
    if (LCombatTypeConst.COMBAT_MAIN == _combatType) then
        return self:GetInstanceMonsterId()
    elseif (LCombatTypeConst.COMBAT_DUNGEON_DAILY == _combatType) then
        return self:GetDungeonDailyMonsterId(battleData)
    elseif (LCombatTypeConst.COMBAT_TOWER_BATTLE == _combatType) then
        return self:GetTowerMonster(_combatType)
    elseif (LCombatTypeConst.COMBAT_TOWER_WATER == _combatType) then
        return self:GetTowerMonster(_combatType)
    elseif (LCombatTypeConst.COMBAT_TOWER_FIRE == _combatType) then
        return self:GetTowerMonster(_combatType)
    elseif (LCombatTypeConst.COMBAT_TOWER_WIND == _combatType) then
        return self:GetTowerMonster(_combatType)
    elseif (LCombatTypeConst.COMBAT_TOWER_LIGHT_DARK == _combatType) then
        return self:GetTowerMonster(_combatType)
        --elseif(LCombatTypeConst.COMBAT_TYPE_75 == _combatType)then
        --	return self:GetTowerMonster(_combatType)
    elseif (LCombatTypeConst.COMBAT_GUILD_BRAVE == _combatType) then
        return self:GetGuildBraveMonster()
        -- 【G公共支持】删掉联盟领主玩法
        -- elseif(LCombatTypeConst.COMBAT_TYPE_32 == _combatType)then
        -- 	return self:GetGuildBossMonster()
    elseif (LCombatTypeConst.COMBAT_CRUSADE_AGAINST == _combatType) then
        return self:GetCrusadeAgainstMonster(battleData)
    elseif (LCombatTypeConst.COMBAT_ACTIVITY == _combatType) then
        return self:GetActivityMonsterId(battleData)
    elseif (LCombatTypeConst.COMBAT_FAIRYLAND_BOSS == _combatType or LCombatTypeConst.COMBAT_HALLOWEEN_BOSS == _combatType or LCombatTypeConst.COMBAT_SWEETCOUNTRY_BOSS == _combatType) then
        return self:GetFairylandMonsterId(battleData)
    elseif (LCombatTypeConst.COMBAT_NEW_HERO_THEME_CHAPTER == _combatType) then
        return self:GetActivityMonsterId(battleData)
        -- elseif(LCombatTypeConst.COMBAT_NEW_HERO_THEME_B_CHAPTER == _combatType)then
        -- 	return self:GetActivityMonsterId(battleData)
    elseif (LCombatTypeConst.COMBAT_ACTIVITY_PLOT_COPY == _combatType) then
        return self:GetActivityMonsterId(battleData)
    elseif self:IsEndlessCombat(_combatType) then
        return self:GetEndlesMonster(_combatType)
    elseif _combatType == LCombatTypeConst.COMBAT_INVASION_BOSS then
        return gModelInvasion:GetCurBossFormation()
    elseif (LCombatTypeConst.COMBAT_TACTICAL_TRAINING == _combatType) then
        local targetId = battleData.targetId
        local ref = gModelCareSchool:GetCollegeLibraryCheckpointRefByRefId(targetId)
        return ref.monster
    elseif (LCombatTypeConst.COMBAT_TACTICAL_SIMULATION == _combatType) then
        local targetId = battleData.targetId
        local monster = gModelCareSchool:GetSimulationBattleData(targetId)
        return monster
    elseif (LCombatTypeConst.COMBAT_TYPE_23 == _combatType) then
        return battleData.monster
    elseif _combatType == LCombatTypeConst.COMBAT_TYPE_75 then
        local monsterIdList = gModelTower:GetTowerLayerMonstorLen(ModelTower.RACE_TYPE_99)
        local teamIndex = 1
        if battleData and battleData.curTeam then
            teamIndex = battleData.curTeam + 1
        end
        return monsterIdList[teamIndex]
    elseif gModelInstance:IsMainLineCombat(_combatType) then
        local monsterArr = gModelInstance:GetBattlePreMonsterArrByCombatType(_combatType)
        local teamIndex = 1
        if battleData and battleData.curTeam then
            teamIndex = battleData.curTeam + 1
        end
        return monsterArr[teamIndex]
    elseif _combatType == LCombatTypeConst.COMBAT_DREAMTRIP then
        local bossId = battleData.bossId
        if bossId then
            return bossId
        end
    elseif _combatType == LCombatTypeConst.COMBAT_WAR_TEMPLE then
        return battleData.monsterRefId
    elseif _combatType == LCombatTypeConst.COMBAT_CROSS_WAR then
        return battleData.monsterRefId

        -- elseif _combatType == LCombatTypeConst.COMBAT_TYPE_34 then【G公共支持】删除本命英雄功能
        -- 	local monsterId = gModelNaturalPartner:GetCurSeleMonsterFormationId()
        -- 	if monsterId then
        -- 		return monsterId
        -- 	end
        -- elseif _combatType == LCombatTypeConst.COMBAT_TYPE_36 then
        -- 	local teamIndex = 1
        -- 	if battleData and battleData.curTeam then
        -- 		teamIndex = battleData.curTeam + 1
        -- 	end
        -- local monsterId = gModelHighStageRace:GetCurMonsterFormationId(teamIndex)
        -- if monsterId then
        -- 	return monsterId
        -- end
    elseif _combatType == LCombatTypeConst.COMBAT_BADGE_GAME then
        return battleData.monsterRefId
    elseif _combatType == LCombatTypeConst.COMBAT_ACTIVITY_155 then
        return battleData.monsterRefId
    elseif _combatType == LCombatTypeConst.COMBAT_TYPE_47 then
        return battleData.monsterRefId
    else
        -- local isBossTowerCombat = gModelBossTower:IsBossTowerCombat(_combatType)
        -- if isBossTowerCombat then
        -- 	local teamIndex = battleData.monsterIndex or 1
        -- 	local bossId = battleData.bossId
        -- 	if bossId then
        -- 		local bossTowerFormationRefId = gModelBossTower:GetSplitBossTowerBossByRefIdAndIndex(bossId,teamIndex,_combatType)
        -- 		if bossTowerFormationRefId then
        -- 			return bossTowerFormationRefId
        -- 			--return gModelHero:GetMonsterList(bossTowerFormationRefId)
        -- 		end
        -- 	end
        -- end
    end
    return 0
end

