        return 0
    end
    local endlessInfo = gModelEndles:GetEndlesData(specialType)
    if not endlessInfo then
        return 0
    end
    local node = endlessInfo.nowNode > 0 and endlessInfo.nowNode or endlessInfo.initNode
    local ref = gModelEndles:GetEndlessCheckpointRefByRefId(node)
    return ref.monster
end

