            heroData.skin = data.skin
        end
    elseif combatType == LCombatTypeConst.COMBAT_WONDERLAND then
        local data = gModelWonderland:GetHeroData(id)
        if data then
            heroData.refId = data.refId
            heroData.skin = data.skin
        end
        -- elseif combatType == LCombatTypeConst.COMBAT_DESIRETRAIL then
        --     local data = gModelDesireTrail:GetHeroData(id)
        --     if data then
        --         heroData.refId = data.refId
        --         heroData.skin = data.skin
        --     end

        --elseif self:IsTimeCorridorCombat(combatType) then
        --	local data =  gModelTimeCorridor:GetHeroData(id)
        --	if data then
        --		heroData.refId = data.refId
        --		heroData.skin = data.skin
        --	end
    elseif combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING then
        local data = gModelHero:GetMonsterAttrByRefId(id)
        if data then
            heroData.refId = data.refId
            heroData.isMonster = true
        end
        -- elseif gModelBossTower:IsBossTowerCombat(combatType) then
        -- 	local bossTowerRef = gModelBossTower:GetBossTowerHeroRefByRefId(tonumber(id))
        -- 	if bossTowerRef then
        -- 		heroData.refId = bossTowerRef.type
        -- 	end
    else
        local data = gModelHero:GetHeroById(id)
        if data then
            heroData.refId = data:GetRefId()
            heroData.skin = data:GetSkin()
        end
    end

    return heroData
end

function ModelBattle:ParseConfig()
    local speedConfig = self:GetCombatConfigRef("addSpeed")
    local strs = string.split(speedConfig, ',')
    local recordNotAutoSpeedLvMap = {}
    local recordNotAutoSpeedVipMap = {}
    local speedList = {}
    --- 1=1=0=1=0,1.5=0=0=0=4,1.8=0=2=1=17,2=0=3=1=52
    for k, v in ipairs(strs) do
        local numbers = LxDataHelper.ParseNumber_Sign(v, '=')
        if #numbers >= 3 then
            local autoState = tonumber(numbers[4]) or 0
            local customsNum = tonumber(numbers[5]) or 0
            local data = {
                timeScale = numbers[1],
                lvLimit = numbers[2],
                vipLimit = numbers[3],
                isAutoState = autoState == 1,
                customsNum = customsNum,
            }

            if not data.isAutoState then
                recordNotAutoSpeedLvMap[data.lvLimit] = k
                recordNotAutoSpeedVipMap[data.vipLimit] = k
            end

            table.insert(speedList, data)
        end
    end

    self._speedList = speedList
    self._recordNotAutoSpeedLvMap = recordNotAutoSpeedLvMap
    self._recordNotAutoSpeedVipMap = recordNotAutoSpeedVipMap
end

function ModelBattle:GetBattleSpeed(combatType, initSpeed, isGuideEd)
    local speedIndex = 1
    if self._maxSpeedCombat[combatType] then
        speedIndex = #self._speedList
    elseif combatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO_SIMULATION then
        speedIndex = initSpeed or 1
    else
        local curSpeed, maxSpeed = self:GetBattleUnitFightSpeed()
        local max = self:GetMaxSpeed(combatType, nil, isGuideEd)
        if maxSpeed and maxSpeed >= max then
            if curSpeed > max then
                speedIndex = curSpeed
                self:SetBattleUnitFightSpeed(speedIndex, maxSpeed)
            else
                speedIndex = curSpeed
            end
        else
            speedIndex = max
            self:SetBattleUnitFightSpeed(speedIndex, max)
        end

    end

    local data = self._speedList[speedIndex]
    if data then
        return data.timeScale, speedIndex
    end
    return 1, 1
end

function ModelBattle:GetUnitBattleSpeed(combatType, initSpeed)
    local speedIndex = 1
    if self._maxSpeedCombat[combatType] then
        speedIndex = #self._speedList
    elseif combatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO_SIMULATION then
        speedIndex = initSpeed or 1
    else
        local curSpeed, maxSpeed = self:GetBattleUnitFightSpeed()
        speedIndex = curSpeed
    end

    local data = self._speedList[speedIndex]
    if data then
        return data.timeScale, speedIndex
    end
    return 1, 1

end

function ModelBattle:CheckIsFirstUseSpeed(curSpeed)
    local firstUseSpeed = tonumber(LPlayerPrefs.firstUseSpeed) or 1
    local isCurUseSpeed = false
    if firstUseSpeed < curSpeed then
        isCurUseSpeed = true
        LPlayerPrefs.SetFirstUseSpeed(tostring(curSpeed))
    end
    return isCurUseSpeed
end

function ModelBattle:GetMaxSpeed(combatType, initMax, isGuideEd, isGuideClickSpeed)
    local maxSpeedIndex = 1
    local cfgMax = #self._speedList
    if self._maxSpeedCombat[combatType] then
        maxSpeedIndex = cfgMax
    elseif combatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO_SIMULATION then
        maxSpeedIndex = initMax or cfgMax
    else

        local lv = gModelPlayer:GetPlayerLv()
        local vipLv = gModelPlayer:GetVipLevel()

        for k, v in ipairs(self._speedList) do
            --- 2024/5/29：修改
            -- 1=1=0=1,1.5=3=0=0,1.8=15=2=1,2=30=3=1
            -- http://192.168.16.2:3002/issues/620
            -- 加速倍数=解锁等级（0为不判断）=VIP解锁等级（任意达成一个即可解锁）=是否自动切换到最大倍数（0否1是）=通关N关卡解锁（与等级和VIP为或关系，0为不判断）
            -- 不动 等级 为0时的判断
            local lvLimit = v.lvLimit
            local needCheckLv = lvLimit > 0
            local customsNum = v.customsNum
            if v.isAutoState or isGuideClickSpeed then
                local isPass = false
                if customsNum and customsNum > 0 then
                    isPass = gModelFunctionOpen:CheckBattleNum(customsNum)
                end
                if not isPass then
                    if needCheckLv then
                        if lv < v.lvLimit and vipLv < v.vipLimit then
                            break
                        end
                    else
                        if vipLv < v.vipLimit then
                            break
                        end
                    end
                end
            else
                local needCheck = true
                if customsNum and customsNum > 0 then
                    local isPass = gModelFunctionOpen:CheckBattleNum(customsNum)
                    if isPass then
                        needCheck = false
                    end
                    if not isPass then
                        break
                    elseif isGuideEd then
                        break
                    end
                end
                if needCheck then
                    if needCheckLv then
                        if lv < v.lvLimit and vipLv < v.vipLimit then
                            break
                        end
                    else
                        if vipLv < v.vipLimit then
                            break
                        end
                    end
                end
            end
            maxSpeedIndex = k
        end
    end
    local isUseMax = false
    if not isGuideClickSpeed and not isGuideEd then
        isUseMax = true
    end
    if isUseMax then
        local curSpeed, maxSpeed = self:GetBattleUnitFightSpeed()
        if curSpeed > maxSpeedIndex then
            maxSpeedIndex = curSpeed
        end
    end
    return maxSpeedIndex
end

