function ModelBattle:AddSpeed(combatType, initMax, curSpeed, isGuideClickSpeed)
    local maxSpeedIndex = self:GetMaxSpeed(combatType, initMax, nil, isGuideClickSpeed)
    local nextSpeed = curSpeed + 1
    if nextSpeed > maxSpeedIndex then
        nextSpeed = 1
    end

    local needSave = true
    local showTip = false
    if self._maxSpeedCombat[combatType] then
        needSave = false
    elseif combatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO_SIMULATION then
        needSave = false
    else
        showTip = true
    end

    if needSave then
        self:SetBattleUnitFightSpeed(nextSpeed, maxSpeedIndex)
    end

    if showTip then
        local realNext = curSpeed + 1
        if realNext > #self._speedList then
            realNext = 1
        end
        if realNext ~= nextSpeed then
            local data = self._speedList[realNext]
            local lv = gModelPlayer:GetPlayerLv()
            local vipLv = gModelPlayer:GetVipLevel()
            local str
            local lock = false
            local needCheckLv = data.lvLimit > 0
            local params = {}
            if needCheckLv then
                if lv < data.lvLimit and vipLv < data.vipLimit then
                    if data.lvLimit > 0 then
                        table.insert(params, string.replace(ccClientText(17811), data.lvLimit))
                    end
                    if data.vipLimit > 0 then
                        table.insert(params, string.replace(ccClientText(17810), data.vipLimit))
                    end
                    --[[					local t = {
						["a1"]= tostring(data.lvLimit),
						["a2"]= tostring(data.vipLimit),
						["a3"]= tostring(realNext),
					}
					str = string.gsub(ccClientText(17804),"#(%w+)#",t)]]
                    lock = true
                end
            else
                local passCustoms = false
                local hasMissionLimit = false
                if data.customsNum and data.customsNum > 0 then
                    hasMissionLimit = true
                    if not gModelFunctionOpen:CheckBattleNum(data.customsNum) then
                        local missStr = ""
                        local missionRef = gModelInstance:GetMissionRefByNum(data.customsNum)
                        if missionRef then
                            table.insert(params, string.replace(ccClientText(16344), missionRef.belongChapterId, missionRef.sort))
                            --missStr = string.replace(ccClientText(16344),missionRef.belongChapterId,missionRef.sort)
                        end
                        if data.lvLimit > 0 then
                            table.insert(params, string.replace(ccClientText(17811), data.lvLimit))
                        end
                        if data.vipLimit > 0 then
                            table.insert(params, string.replace(ccClientText(17810), data.vipLimit))
                        end
                        --[[						local t = {
							["a1"]= missStr,
							["a2"]= tostring(data.vipLimit),
							["a3"]= tostring(realNext),
						}
						str = string.gsub(ccClientText(17807),"#(%w+)#",t)]]
                        lock = true
                    else
                        passCustoms = true
                    end
                end
                if not lock and not passCustoms then
                    if vipLv < data.vipLimit then
                        if hasMissionLimit then
                            local missStr = ""
                            local missionRef = gModelInstance:GetMissionRefByNum(data.customsNum)
                            if missionRef then
                                table.insert(params, string.replace(ccClientText(16344), missionRef.belongChapterId, missionRef.sort))
                                --missStr = string.replace(ccClientText(16344),missionRef.belongChapterId,missionRef.sort)
                            end
                            if data.lvLimit > 0 then
                                table.insert(params, string.replace(ccClientText(17811), data.lvLimit))
                            end
                            if data.vipLimit > 0 then
                                table.insert(params, string.replace(ccClientText(17810), data.vipLimit))
                            end
                            --[[							local t = {
								["a1"]= missStr,
								["a2"]= tostring(data.vipLimit),
								["a3"]= tostring(realNext),
							}
							str = string.gsub(ccClientText(17807),"#(%w+)#",t)]]
                        else
                            if data.lvLimit > 0 then
                                table.insert(params, string.replace(ccClientText(17811), data.lvLimit))
                            end
                            if data.vipLimit > 0 then
                                table.insert(params, string.replace(ccClientText(17810), data.vipLimit))
                            end
                            --[[							local t = {
								["a1"]= tostring(data.vipLimit),
								["a2"]= tostring(realNext),
							}
							str = string.gsub(ccClientText(17806),"#(%w+)#",t)]]
                        end
                        lock = true
                    end
                end
            end
            if lock then
                if #params > 0 then
                    str = string.replace(ccClientText(17808), table.concat(params, ccClientText(17809)), realNext)
                end
            else
                if data.customsNum and data.customsNum > 0 then
                    if not gModelFunctionOpen:CheckBattleNum(data.customsNum) then
                        local missionRef = gModelInstance:GetMissionRefByNum(data.customsNum)
                        if missionRef then
                            str = string.replace(ccClientText(16344), missionRef.belongChapterId, missionRef.sort)
                        end
                    end
                end
            end
            if str then
                GF.ShowMessage(str)
            end
        end
    end

    local data = self._speedList[nextSpeed]
    return data.timeScale, nextSpeed
end

function ModelBattle:CanSkip(combatType, showTips, targetId)

    local privilegeType = 28
    local effIdList = gModelGeneral:GetSysEffListByType(privilegeType)
    for k, v in ipairs(effIdList) do
        local refId = v.refId
        local isActive = gModelGrade:GetIsActivatePrivilege(refId)
        if isActive then
            local cfg = v
            local effectStr = cfg.effectValue
            local types = LxDataHelper.ParseNumber_Sign(effectStr, ",")
            for k1, v1 in ipairs(types) do
                if combatType == v1 then
                    return true
                end
            end
        end
    end

    local dataMap = self:GetPrivilegeEff_31()
    local data = dataMap and dataMap[combatType]
    if data then
        local skipRecord = self._skipInfoRecords and self._skipInfoRecords[combatType]
        if skipRecord then
            local cdTime = skipRecord.cdTime or 0
            local leftTime = cdTime - GetTimestamp()
            local canSkip = leftTime <= 0 or data.times > skipRecord.failCnt
            if not canSkip then
                if showTips and leftTime > 0 then
                    local timeStr = LUtil.FormatTimespanCn(leftTime)
                    local str = ccClientText(16610)  --"%s后可以跳过"
                    local showStr = string.replace(str, timeStr)
                    GF.ShowMessage(showStr)
                end
            end

            if leftTime <= 0 and skipRecord.failCnt >= data.times then
                --惩罚结束，清空计数
                self:ClearFailCnt(combatType)
            end

            return canSkip
        else
            return true
        end
    end

    local combatRef = GameTable.BattleGameRef[combatType]
    if not combatRef then
        return true
    end
    local skipLimit = combatRef.skipOpen
    local tempStrs = string.split(skipLimit, ",")
    local type = nil
    local para = nil
    for k, v in ipairs(tempStrs) do
        local numbers = LxDataHelper.ParseNumber_Sign(v, '=')
        if #numbers > 0 then
            type = numbers[1]
            if type == 2 then
                local lv = numbers[2]
                local playerLv = gModelPlayer:GetPlayerLv()
                if playerLv >= lv then
                    para = numbers[3]
                end
            else
                para = numbers[2]
            end
        end
    end

    if type == 1 then
        local level = gModelPlayer:GetPlayerLv()
        if level < para then
            if showTips then
                GF.ShowMessage(string.replace(ccClientText(17800), para))
            end
            return false
        end
    elseif type == 2 then
        local times = gModelArena:GetSeasonChallengeTimes()
        if times < para then
            if showTips then
                local lack = para - times
                GF.ShowMessage(string.replace(ccClientText(10344), lack))
            end
            return false
        end
    elseif type == 3 then
        local chanllgeTime = gModelGuildBoss:GetTodayBattleCnt()
        if chanllgeTime <= para then
            if showTips then
                GF.ShowMessage(string.replace(ccClientText(17801), para))
            end
            return false
        end
    elseif type == 4 then
        if showTips then
            local gradeRef = ModelGrade:GetGradeLvRefByRefId(para)
            local name = ccLngText(gradeRef.name)
            local str = ccClientText(17803)
            GF.ShowMessage(string.replace(str, name))
        end
        return false
        --elseif type == 5 then
        --	local ref = gModelCrusadeAgainst:GetDreamCrusadeCheckpointRefByRefId(targetId)
        --	local isSkip = false
        --	if ref then
        --		local difficulty = ref.difficulty
        --		if difficulty >= para then
        --			isSkip = true
        --		end
        --	end
        --	if showTips and not isSkip then
        --		GF.ShowMessage(string.replace(ccClientText(32344),para))
        --	end
        --	return isSkip
    elseif type == 6 then
        local refId = tonumber(para)
        local missionRef = gModelInstance:GetMissionCfg(refId)
        if not missionRef then
            return false
        end
        local belongChapterId = missionRef.belongChapterId
        local chapterRef = gModelInstance:GetInstanceChapterRefByRefId(belongChapterId)
        local difficulty = chapterRef.type
        local chapterId = gModelInstance:GetChapterIdByPbIdAndDiffLvlData(difficulty)
        local battleNum = gModelInstance:GetBattleNumByPbIdAndDiffLvlData(difficulty)
        local isSkip = true
        if chapterId < belongChapterId then
            isSkip = false
        elseif chapterId == belongChapterId and missionRef.num >= battleNum then
            isSkip = false
        end
        if not isSkip then
            GF.ShowMessage(string.replace(ccClientText(16344), missionRef.num, ccLngText(missionRef.nameWorld)))
        end
        return isSkip
    end
    return true
end

function ModelBattle:RecordFail(combatType)
    local dataMap = self:GetPrivilegeEff_31()
    local data = dataMap[combatType]
    if not data then
        printInfoN("no privilege 31")
        return
    end

    if not self._skipInfoRecords then
        self._skipInfoRecords = {}
    end
    local skipRecord = self._skipInfoRecords[combatType] or {}
    local isInCd = skipRecord.cdTime and skipRecord.cdTime > GetTimestamp()
    if isInCd then
        return
    end
    local failCnt = skipRecord.failCnt or 0
    failCnt = failCnt + 1
    if failCnt >= data.times then
        skipRecord.cdTime = GetTimestamp() + data.cd * 60
    end
    skipRecord.failCnt = failCnt
    --todo save
    self._skipInfoRecords[combatType] = skipRecord

    printInfoN(string.format("fail cnt %s  type %s", failCnt, combatType))
    local str = JSON.encode(self._skipInfoRecords)
    LPlayerPrefs.SetSkipPriviRecord(str)
end

function ModelBattle:ClearFailCnt(combatType)
    local dataMap = self:GetPrivilegeEff_31()
    local data = dataMap[combatType]
    if not data then
        printInfoN("no privilege 31")
        return
    end

    if not self._skipInfoRecords then
        return
    end

    local data = self._skipInfoRecords[combatType]
    if not data then
        return
    end
    data.failCnt = 0
    data.cdTime = 0
    self._skipInfoRecords[combatType] = data
    local str = JSON.encode(self._skipInfoRecords)
    LPlayerPrefs.SetSkipPriviRecord(str)
end

function ModelBattle:InitSkipRecord()
    local str = LPlayerPrefs.skipPriviRecord
    if string.isempty(str) then
        return
    end

    local recordList = JSON.decode(str)
    self._skipInfoRecords = recordList
end

function ModelBattle:GetPrivilegeEff_31()
    local privilegeType = 31
    local effIdList = gModelGeneral:GetSysEffListByType(privilegeType)
    local dataMap = {}
    for k, v in ipairs(effIdList) do
        local refId = v.refId
        local isActive = gModelGrade:GetIsActivatePrivilege(refId)
        if isActive then
            local effectValue = gModelGeneral:GetSysEffectValue(refId)
            gModelGeneral:ParsePriviValue_31(effectValue, dataMap)
        end
    end

    return dataMap
end

function ModelBattle:IsCombatLifeFinish(combatType)

    if self:IsBattleAlive(combatType) then
        return false
    end

    return true
end

---记录战斗生命周期 从发起战斗到结算协议为止
function ModelBattle:RecordBattleLife(combatType, isAlive)
    if not self._battleLifeRecord then
        self._battleLifeRecord = {}
    end
    self._battleLifeRecord[combatType] = isAlive
end

---回放或者观看战斗生命周期记录
function ModelBattle:RecordVideoBattleLife(combatType, isAlive)
    if not self._videoLifeRecord then
        self._videoLifeRecord = {}
    end
    self._videoLifeRecord[combatType] = isAlive
    if LOG_INFO_ENABLED then
        print(string.format("combat %s life %s", tostring(combatType), tostring(isAlive)))
    end
end

function ModelBattle:IsBattleAlive(combatType)
    return self._battleLifeRecord and self._battleLifeRecord[combatType]
end

function ModelBattle:IsVideoAlive()
    if self._videoLifeRecord then
        for k, v in pairs(self._videoLifeRecord) do
            if v then
                return true
            end
        end
    end
    return false
end

function ModelBattle:IsLevelUpShowOrWait()

    if not self:IsCombatLifeFinish(LCombatTypeConst.COMBAT_MAIN) then
        return true
    end

    if self._curWnd then
        return true
    end

    local has = self:HasLevelUpWnd()
    return has
end

function ModelBattle:IsDelayShowCombat(combatType)
    if not (GF.FindFirstWndByName("UIFightPrepare") or GF.FindFirstWndByName("UIFight")) then
        return false
    end

    local curMap = GF.GetCurMap()
    if not curMap then
        return false
    end
    if not curMap:IsSameMap("LBattleMap") then
        return false
    end

    local curCombatType = curMap:GetCombatType()
    local ref = gModelFormation:GetCombatGameRef(curCombatType)
    if not ref or ref.delayShow ~= 1 then
        return false
    end

    if combatType and curCombatType == combatType then
        return false
    end

    return true
end

