function ModelBattle:GetOtherNameByCombatResult(combatResult)
    if not combatResult then
        return ""
    end
    local combatType = combatResult.combatType
    local otherName = ""

    local eventId = combatResult.wonderlandEventRefId
    if combatType == LCombatTypeConst.COMBAT_WONDERLAND then
        otherName = gModelWonderland:GetEventName(eventId)
    elseif combatType == LCombatTypeConst.COMBAT_DESIRETRAIL then
        otherName = gModelDesireTrail:GetEventName(eventId)
        --elseif self:IsTimeCorridorCombat(combatType) then
        --	otherName = gModelTimeCorridor:GetEventName(eventId)
    elseif combatType == LCombatTypeConst.COMBAT_INVASION then
        otherName = gModelInvasion:GetEventName(eventId)
    elseif combatType == LCombatTypeConst.COMBAT_DREAMTRIP then
        otherName = gModelFastDreamTrip:GetDreamTripEventNameByRefId(eventId)
    else
        local monsterId = combatResult.monsterId and tonumber(combatResult.monsterId)
        if monsterId > 0 then
            local monsterFormationRef = gModelHero:GetMonsterFormationRefByRefId(monsterId)
            if monsterFormationRef then
                otherName = ccLngText(monsterFormationRef.name)
            end
        else
            otherName = combatResult.targetName
        end
    end

    return otherName

end

function ModelBattle:RecordReportPrepare(combatType, reportId)
    if not self._okReportMap then
        self._okReportMap = {}
    end

    local record = self._okReportMap[combatType]
    if not record then
        return
    end

    if LOG_INFO_ENABLED then
        print(string.format("<color=red>record report prepare %s</color>", combatType))
    end

    local list = self._okReportMap[combatType] or {}
    list[reportId] = true

    self._okReportMap[combatType] = list
end

function ModelBattle:ClearReportPrepare(combatType)
    if LOG_INFO_ENABLED then
        print(string.format("<color=red>clear report prepare %s</color>", combatType))
    end

    if not self._okReportMap then
        self._okReportMap = {}
    end
    self._okReportMap[combatType] = {}
end

function ModelBattle:IsReportPrepare(combatType, reportId)
    local record = self._okReportMap and self._okReportMap[combatType]
    if not record then
        return true
    end

    return record[reportId] or false
end
function ModelBattle:IsReportPrepare2(combatType, reportId)
    local record = self._okReportMap and self._okReportMap[combatType]
    if not record then
        return true
    end
    for i, v in ipairs(reportId) do
        local bool = self:IsReportPrepare(combatType, v)
        if not bool then
            return false
        end
    end
    return true
end

---通用战斗跳过流程  --已添加 时光回廊，
---注意战斗参数和GetOnFormationHeroCnt
function ModelBattle:StartBattleRundown(rundownData, skipBattleData, battleData)

    local isSkip = rundownData.skipBattle
    local combatType = rundownData.combatType

    local skipBattleFunc = function()
        local combatData = {
            combatType = combatType,
            targetId = skipBattleData.targetId,
            battleRefId = skipBattleData.battleRefId,
            x = skipBattleData.x,
            y = skipBattleData.y,
            skipBattle = true,
        }
        self:OnCombatReq(combatData)
        if rundownData.skipEndCall then
            rundownData.skipEndCall()
        end
    end

    local prepareFunc = function()
        gLFightManager:PrepareGoToBattle(combatType, battleData)
        if rundownData.skipEndCall then
            rundownData.skipEndCall()
        end
    end

    if isSkip then
        local heroCnt = self:GetOnFormationHeroCnt(combatType)
        if heroCnt > 0 and heroCnt < 5 then
            local para = {
                refId = 200005,
                func = skipBattleFunc,
                leftFunc = prepareFunc,
            }
            gModelGeneral:OpenUIOrdinTips(para)
        elseif heroCnt == 0 then
            local para = {
                refId = 200009,
                func = prepareFunc,
            }
            gModelGeneral:OpenUIOrdinTips(para)
        else
            skipBattleFunc()
        end
    else
        prepareFunc()
    end
end

