function ModelBattle:GetIsSkipBattlePrepare(combatType)
    local towerSaveBattle = LPlayerPrefs.towerSaveBattle
    local arr = string.split(towerSaveBattle, "|")
    if #arr > 0 then
        for i, v in ipairs(arr) do
            local valueArr = string.split(v, "=")
            if #valueArr > 1 then
                if tonumber(valueArr[1]) == combatType then
                    return valueArr[2] == "1"
                end
            end
        end
    end
    return false
end
function ModelBattle:SetIsSkipBattlePrepare(combatType, isSkip)
    local value = combatType .. "=" .. (isSkip and 1 or 0)

    local towerSaveBattle = LPlayerPrefs.towerSaveBattle
    local arr = string.split(towerSaveBattle, "|")
    if #arr > 0 then
        for i, v in ipairs(arr) do
            local valueArr = string.split(v, "=")
            if #valueArr > 1 then
                if tonumber(valueArr[1]) ~= combatType then
                    value = value .. "|" .. v
                end
            end
        end
    end
    LPlayerPrefs.SetTowerSaveBattle(value)
end

function ModelBattle:StartContinueBattle(combatType, combatData)
    local battlePlay = self:GetBattlePlay(combatType)
    if battlePlay then
        if battlePlay:CheckCanReplace() then
            battlePlay:Destroy()
        else
            return
        end
    end

    battlePlay = LFightPlayContinue:New()
    self:SaveBattlePlay(combatType, battlePlay)
    battlePlay:Start(combatType, combatData)
end

