function ModelBattle:GetTipShowReward(wndData)
    local wndType = wndData.accWndType or 1
    local itemList = nil
    if wndType == 3 then
        itemList = wndData.towerData.itemList
    elseif wndType == 2 then
        itemList = wndData.guildData.reward
    elseif wndType == 1 then
        itemList = wndData.combatResult.itemList
    elseif wndType == 4 then
        itemList = wndData.invasionData.reward
    end

    local dataList = {}
    if itemList then
        for k, v in ipairs(itemList) do
            local itemId = v.itemId or v.refId
            local itemType = v.type or v.itemType
            local itemNum = tonumber(v.count) or tonumber(v.itemNum)
            if not dataList[itemId] then
                if itemType == LItemTypeConst.TYPE_ITEM
                        or itemType == LItemTypeConst.TYPE_HERO
                        or itemType == LItemTypeConst.TYPE_OUTFIT then
                    dataList[itemId] = {
                        itemId = itemId,
                        itemNum = itemNum,
                        itemType = itemType,
                    }
                end
            else
                local oldNum = dataList[itemId].itemNum
                dataList[itemId].itemNum = oldNum + itemNum
            end
        end
    end

    local cnt = 0
    local resultDataList = {}
    for k, v in pairs(dataList) do
        table.insert(resultDataList, v)
        cnt = cnt + 1
        if cnt >= 4 then
            break
        end
    end

    return resultDataList
end

