---@param refId number buff refId
---@return table|nil buff层数播放特效 格式：层数=特效|…… （从小填到大）
function ModelBattle:GetBuffEffShowNum(refId)
    if not self._initBuffEffShowNumMap then
        self._initBuffEffShowNumMap = {}
    end
    local buffEffShowNumData = self._initBuffEffShowNumMap[refId]
    if buffEffShowNumData then return buffEffShowNumData end

    local ref = self:GetBuffRef(refId)
    if not ref then return end

    if string.isempty(ref.buffEffShowNum) then return end

    buffEffShowNumData = {}
    local buffEffShowNum = string.split(ref.buffEffShowNum,"|")
    for i,v in ipairs(buffEffShowNum) do
        v = string.split(v,"=")
        local pliesNum = checknumber(v[1])
        buffEffShowNumData[pliesNum] = {
            effRes = v[2],
        }
    end
    self._initBuffEffShowNumMap[refId] = buffEffShowNumData
    return buffEffShowNumData
end

---@return boolean 是否为层数显示
function ModelBattle:HasBuffEffShowNum(refId)
    local buffEffShowNumData = self:GetBuffEffShowNum(refId)
    return buffEffShowNumData ~= nil
end

---@return boolean 是否为减伤护盾
function ModelBattle:CheckBuffHasHurtShields(buffRefId)
    local effectIdList = self:GetBuffEffectIDByBuffID(buffRefId)
    if not effectIdList or #effectIdList < 1 then return false end

    local hasHurtShield = false
    local hurt_shields = LBuffStateConst.BUFF_STATE_HURT_SHIELDS
    for i, v in ipairs(effectIdList) do
        local data = self:GetBuffEffectRef(v)
        --类型1：影响英雄的战斗属性
        --类型2：影响英雄的2级状态
        --- 新增判断，需要 effectType == 2 的时候，才可以判断 effectId
        if data.effectType == 2 and data.effectId == hurt_shields then
            hasHurtShield = true
            break
        end
    end
    return hasHurtShield
end

function ModelBattle:CheckBuffEffectIsBomb(buffRefId)
    local effectIdList = self:GetBuffEffectIDByBuffID(buffRefId)
    if not effectIdList or #effectIdList < 1 then return false end

    local hasBomb = false
    local bombEffType = LBuffStateConst.BUFF_STATE_BOMB
    for i, v in ipairs(effectIdList) do
        local data = self:GetBuffEffectRef(v)
        --类型1：影响英雄的战斗属性
        --类型2：影响英雄的2级状态
        --- 新增判断，需要 effectType == 2 的时候，才可以判断 effectId
        if data.effectType == 2 and data.effectId == bombEffType then
            hasBomb = true
            break
        end
    end
    return hasBomb
end


--- 是否为召唤类型的buff
function ModelBattle:CheckBuffEffectIsSummon(buffId)
    local effectIdList = self:GetBuffEffectIDByBuffID(buffId)
    if not effectIdList or #effectIdList < 1 then return false end
    for i,v in ipairs(effectIdList) do
        local data = self:GetBuffEffectRef(v)
        if data.effectType == 2 and data.effectId == 86 then
            return true
        end
    end
    return false
end



return ModelBattle